/* ─── HAVERSINE ─── */
function haversine(lat1, lng1, lat2, lng2) {
  const R = 6371, toR = x => x * Math.PI / 180;
  const dLat = toR(lat2-lat1), dLng = toR(lng2-lng1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toR(lat1))*Math.cos(toR(lat2))*Math.sin(dLng/2)**2;
  return Math.round(R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a)));
}

/* ─── COORDINATE → SVG ─── */
const MAP_W = 600, MAP_H = 270;
function toSVG(lat, lng) {
  const x = ((lng - 94.0) / 48.0) * (MAP_W - 30) + 15;
  const y = ((7.0 - lat) / 19.0) * (MAP_H - 24) + 12;
  return { x, y };
}

/* ─── XML PARSER ─── */
function parseXML(str) { return new DOMParser().parseFromString(str, "text/xml"); }
function xmlText(doc, tag) { const el = doc.querySelector(tag); return el ? el.textContent.trim() : ""; }

/* ─── BMKG FETCH — /api/bmkg dengan fallback proxy ─── */
const PROXY = "https://api.allorigins.win/raw?url=";
const BMKG_URLS = {
  autogempa:      "https://data.bmkg.go.id/DataMKG/TEWS/autogempa.xml",
  gempaterkini:   "https://data.bmkg.go.id/DataMKG/TEWS/gempaterkini.xml",
  gempadirasakan: "https://data.bmkg.go.id/DataMKG/TEWS/gempadirasakan.xml",
};
async function fetchBMKG(type) {
  try {
    const r = await fetch(`/api/bmkg?type=${type}`, { headers: { "Accept": "application/xml" } });
    if (!r.ok) throw new Error();
    return await r.text();
  } catch {
    try {
      const r2 = await fetch(PROXY + encodeURIComponent(BMKG_URLS[type]));
      if (!r2.ok) throw new Error();
      return await r2.text();
    } catch { return null; }
  }
}

/* ─── BMKG CUACA FETCH ─── */
async function fetchWeather(adm4) {
  try {
    const url = `https://api.bmkg.go.id/publik/prakiraan-cuaca?adm4=${adm4}`;
    const r = await fetch(PROXY + encodeURIComponent(url));
    if (!r.ok) throw new Error();
    return await r.json();
  } catch { return null; }
}

function parseAutoGempa(xml) {
  if (!xml) return null;
  const doc = parseXML(xml);
  const lats = xmlText(doc, "Lintang");
  const lngs = xmlText(doc, "Bujur");
  const latV = lats.includes("LS") ? -Math.abs(parseFloat(lats)) : Math.abs(parseFloat(lats));
  const lngV = Math.abs(parseFloat(lngs));
  return {
    tanggal: xmlText(doc,"Tanggal"), jam: xmlText(doc,"Jam"),
    mag: parseFloat(xmlText(doc,"Magnitude")), kedalaman: xmlText(doc,"Kedalaman"),
    lat: latV, lng: lngV, wilayah: xmlText(doc,"Wilayah"),
    potensi: xmlText(doc,"Potensi"), dirasakan: xmlText(doc,"Dirasakan"),
    shakemap: xmlText(doc,"Shakemap"),
  };
}

function parseGempaList(xml, isM5) {
  if (!xml) return [];
  const doc = parseXML(xml);
  return Array.from(doc.querySelectorAll("gempa")).slice(0,15).map((g,i) => {
    const lats = g.querySelector("Lintang")?.textContent||"";
    const lngs = g.querySelector("Bujur")?.textContent||"";
    const latV = lats.includes("LS") ? -Math.abs(parseFloat(lats)) : Math.abs(parseFloat(lats));
    const lngV = Math.abs(parseFloat(lngs));
    return {
      id: i, tanggal: g.querySelector("Tanggal")?.textContent||"",
      jam: g.querySelector("Jam")?.textContent||"",
      mag: parseFloat(g.querySelector("Magnitude")?.textContent||"0"),
      kedalaman: g.querySelector("Kedalaman")?.textContent||"",
      lat: latV, lng: lngV, wilayah: g.querySelector("Wilayah")?.textContent||"",
      potensi: isM5 ? (g.querySelector("Potensi")?.textContent||"") : "",
      dirasakan: !isM5 ? (g.querySelector("Dirasakan")?.textContent||"") : "",
    };
  });
}

/* ─── WHATSAPP TEMPLATE ─── */
function buildWAMessage(gempa, cabangList) {
  const terdampak = cabangList.map(c=>`• ${c.nama} (${c.jarak} km)`).join("\n");
  return `🚨 *ALERT GEMPA - PNM RESPATI*\n\n📅 ${gempa.tanggal} | ⏰ ${gempa.jam} WIB\n📍 *Lokasi:* ${gempa.wilayah}\n💪 *Magnitudo:* M${gempa.mag}\n🏔️ *Kedalaman:* ${gempa.kedalaman}\n⚠️ *Potensi:* ${gempa.potensi||"Tidak berpotensi tsunami"}\n\n🏢 *Cabang Terdampak (dalam radius):*\n${terdampak || "Tidak ada cabang dalam radius"}\n\n🔗 Pantau: BMKG App / bmkg.go.id\n_Dikirim otomatis oleh PNM RESPATI Disaster Monitor_`;
}

